def merge_cluster_data():
  """Merge all cluster data with movies.json."""
  movies_path = Path("/Users/sandeep.srinivasan/sand-ship/indian-movie-genie/backend/data/movies.json")

  # Load existing movies
  with open(movies_path) as f:
    movies = json.load(f)

  # Create lookup: (title, year, language) -> movie
  movie_lookup = {}
  for m in movies:
    key = (m.get("title", "").strip(), m.get("year"), m.get("language", "").strip())
    movie_lookup[key] = m

  # Merge Hindi 90s clusters
  matched = 0
  unmatched = []
  for cluster_film in HINDI_90S:
    key = (cluster_film.get("title", "").strip(), cluster_film["year"], cluster_film["language"])
    if key in movie_lookup:
      movie = movie_lookup[key]
      movie["cluster_id"] = cluster_film["cluster_id"]
      movie["cluster_name"] = cluster_film["cluster_name"]
      movie["cluster_differentiation_key"] = cluster_film["cluster_differentiation_key"]
      movie["cluster_tags"] = cluster_film.get("tags", {})
      matched += 1
    else:
      unmatched.append(cluster_film["title"])

  # Save updated movies
  with open(movies_path, 'w') as f:
    json.dump(movies, f, indent=2)

  print(f"\n✓ Merged {matched} Hindi 90s films with cluster metadata")
  if unmatched:
    print(f"⚠ {len(unmatched)} films not found in movies.json: {unmatched[:5]}...")

  # Count total clustered
  clustered_count = sum(1 for m in movies if "cluster_id" in m)
  print(f"\nTotal films with cluster metadata: {clustered_count}/{len(movies)}")

if __name__ == "__main__":
  merge_cluster_data()
